from collections.abc import Sequence
from dataclasses import dataclass
from typing import ClassVar, final, override

import nacl.signing
from block.generated import ConfigParam
from pytoniq_core import Address, Builder, Cell
from pytoniq_core.tlb.account import TickTock
from tlb.hashmap import HashmapDict
from tlb.object import CellRefType

from .contract import Blueprint, ContractView, Provider


@dataclass
class ConfigState:
    _params: HashmapDict[Cell]
    seqno: int
    public_key: nacl.signing.VerifyKey

    def serialize(self) -> Cell:
        b = Builder()
        # ^config_dict
        config_cell = Builder()
        self._params.serialize_to(config_cell)
        _ = b.store_ref(config_cell.end_cell())
        # seqno
        _ = b.store_uint(self.seqno, 32)
        # public_key
        _ = b.store_bytes(bytes(self.public_key))
        # empty vote dict
        _ = b.store_uint(0, 1)
        return b.end_cell()


class ConfigView(ContractView[ConfigState]):
    _cached_public_key: nacl.signing.VerifyKey | None = None

    @override
    def _parse_state(self, state: Cell) -> ConfigState:
        cs = state.begin_parse()
        config_dict_cell = cs.load_ref()
        params = HashmapDict[Cell].load_from(
            config_dict_cell.begin_parse(), 32, CellRefType, allow_empty=False
        )
        seqno = cs.load_uint(32)
        pubkey_bytes = cs.load_bytes(32)
        if self._cached_public_key is None:
            self._cached_public_key = nacl.signing.VerifyKey(pubkey_bytes)
        return ConfigState(
            _params=params,
            seqno=seqno,
            public_key=self._cached_public_key,
        )


@dataclass
class Config(ConfigView):
    key: nacl.signing.SigningKey


# Compiled from auto/config-code.fif — regenerate with extract_contract_bocs.py
CONFIG_CODE = Cell.one_from_boc(
    ""
)


@final
class ConfigBlueprint(Blueprint[ConfigState]):
    CODE_BOC: ClassVar[Cell] = CONFIG_CODE

    def __init__(
        self,
        params: Sequence[ConfigParam],
        master_key: nacl.signing.SigningKey | None = None,
        workchain: int = -1,
    ):
        if master_key is None:
            master_key = nacl.signing.SigningKey.generate()
        self.master_key = master_key

        config = HashmapDict[Cell](32, CellRefType, allow_empty=False)
        for param in params:
            idx = param.get_output(0)
            assert idx not in config
            config[idx] = param.serialize()

        state = ConfigState(_params=config, seqno=0, public_key=master_key.verify_key)
        super().__init__(workchain, state)
        self.state_init.special = TickTock(tick=False, tock=True)
        self.address = Address((-1, b"\x55" * 32))

    @override
    def materialize(self, provider: Provider):
        return Config(provider, self.address, self.master_key)
